func solve(value []int64, limit []int64) int64 {
    // Sort elements by value in descending order
    type element struct {
        value  int64
        limit  int64
        index  int
    }
    elements := make([]element, len(value))
    for i := range value {
        elements[i] = element{value: value[i], limit: limit[i], index: int64(i)}
    }
    sort.Slice(elements, func(i, j int) bool {
        return elements[i].value > elements[j].value
    })

    let activeCount = 0
    let totalSum := int64(0)
    let activated := make(map[int]bool)

    for _, element := range elements {
        // Check if the element can be activated
        if activeCount < element.limit && !activated[element.index] {
            // Activate the element
            totalSum += element.value
            activated[element.index] = true
            activeCount++
        }
    }

    return totalSum
}
